class SceneState: ObservableObject {
    // === AR References ===
    weak var arView: ARSCNView?
    var placedNodes: [String: SCNNode] = [:]
    var detectedPlanes: [UUID: SCNNode] = [:]

    init() {
        print("[HoloScript] Scene state initialized")
    }

    func placeObject(at transform: simd_float4x4) {
        guard let arView = arView else { return }

        let nodes = GeneratedARSceneObjects.createSceneNodes()
        guard let node = nodes.values.first else { return }

        node.simdWorldTransform = transform
        arView.scene.rootNode.addChildNode(node)

        let id = UUID().uuidString
        placedNodes[id] = node
        print("[HoloScript] Placed object: \(id)")
    }

    func handleNodeTap(_ node: SCNNode) {
        print("[HoloScript] Tapped node: \(node.name ?? "unnamed")")

        // Visual feedback
        let originalScale = node.scale
        SCNTransaction.begin()
        SCNTransaction.animationDuration = 0.1
        node.scale = SCNVector3(originalScale.x * 1.2, originalScale.y * 1.2, originalScale.z * 1.2)
        SCNTransaction.commit()

        DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) {
            SCNTransaction.begin()
            SCNTransaction.animationDuration = 0.1
            node.scale = originalScale
            SCNTransaction.commit()
        }
    }

    func didDetectPlane(_ anchor: ARPlaneAnchor, node: SCNNode) {
        let plane = SCNPlane(width: CGFloat(anchor.planeExtent.width), height: CGFloat(anchor.planeExtent.height))
        plane.firstMaterial?.diffuse.contents = UIColor.white.withAlphaComponent(0.3)

        let planeNode = SCNNode(geometry: plane)
        planeNode.eulerAngles.x = -.pi / 2
        planeNode.position = SCNVector3(anchor.center.x, 0, anchor.center.z)

        node.addChildNode(planeNode)
        detectedPlanes[anchor.identifier] = planeNode
    }

    func didUpdatePlane(_ anchor: ARPlaneAnchor, node: SCNNode) {
        guard let planeNode = detectedPlanes[anchor.identifier],
              let plane = planeNode.geometry as? SCNPlane else { return }

        plane.width = CGFloat(anchor.planeExtent.width)
        plane.height = CGFloat(anchor.planeExtent.height)
        planeNode.position = SCNVector3(anchor.center.x, 0, anchor.center.z)
    }

    func resetScene() {
        guard let arView = arView else { return }

        // Remove placed nodes
        for node in placedNodes.values {
            node.removeFromParentNode()
        }
        placedNodes.removeAll()

        // Reset AR session
        let configuration = ARWorldTrackingConfiguration()
        configuration.planeDetection = [.horizontal, .vertical]
        arView.session.run(configuration, options: [.resetTracking, .removeExistingAnchors])

        print("[HoloScript] Scene reset")
    }
